// ── Step 2: Validate & Transform ─────────────────────────────
const items = $input.all();
const processed = [];
const rejected = [];

const VALID_PRIORITIES = ['high', 'medium', 'low'];
const VALID_ISSUE_TYPES = ['wifi', 'login', 'software', 'hardware', 'other'];

function validateEmail(email) {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

function generateID() {
  return 'TKT-' + Math.random().toString(36).substr(2, 8).toUpperCase();
}

function normalizeName(name) {
  return name.trim().split(' ').map(w => w.charAt(0).toUpperCase() + w.slice(1).toLowerCase()).join(' ');
}

// Dedup store (in-memory for this execution)
const seen = {};

for (const item of items) {
  const data = item.json;
  const ticketId = generateID();
  const timestamp = data.timestamp ? new Date(data.timestamp) : new Date();

  const name = (data.name || '').trim();
  const email = (data.email || '').trim().toLowerCase();
  const issueType = (data.issue_type || '').trim().toLowerCase();
  const priority = (data.priority || '').trim().toLowerCase();
  const description = (data.description || '').trim();

  // Validate email
  if (!email || !validateEmail(email)) {
    rejected.push({
      ticket_id: ticketId,
      name: normalizeName(name) || 'Unknown',
      email: email || '(missing)',
      reason: 'Invalid or missing email address',
      timestamp: timestamp.toISOString(),
    });
    continue;
  }

  // Validate priority
  if (!VALID_PRIORITIES.includes(priority)) {
    rejected.push({
      ticket_id: ticketId,
      name: normalizeName(name),
      email,
      reason: `Invalid priority: '${data.priority}'. Must be High/Medium/Low`,
      timestamp: timestamp.toISOString(),
    });
    continue;
  }

  // Validate issue type
  if (!VALID_ISSUE_TYPES.includes(issueType)) {
    rejected.push({
      ticket_id: ticketId,
      name: normalizeName(name),
      email,
      reason: `Unknown issue type: '${data.issue_type}'`,
      timestamp: timestamp.toISOString(),
    });
    continue;
  }

  // Deduplicate (same email + issue_type within 24h)
  const dedupKey = `${email}|${issueType}`;
  if (seen[dedupKey]) {
    const diffHours = (timestamp - seen[dedupKey]) / 3600000;
    if (diffHours < 24) {
      rejected.push({
        ticket_id: ticketId,
        name: normalizeName(name),
        email,
        reason: `Duplicate ticket: same email+issue submitted ${diffHours.toFixed(1)}h ago`,
        timestamp: timestamp.toISOString(),
      });
      continue;
    }
  }
  seen[dedupKey] = timestamp;

  processed.push({
    ticket_id: ticketId,
    name: normalizeName(name),
    email,
    issue_type: issueType,
    priority: priority.charAt(0).toUpperCase() + priority.slice(1),
    description,
    timestamp: timestamp.toISOString(),
    _valid: true,
  });
}

// Output both arrays for downstream routing
return [{ json: { processed, rejected } }];

// ── Step 3: Route to Team + Step 4: Calculate SLA ────────────
const { processed, rejected } = $input.first().json;

const ROUTING = {
  wifi:     'Network',
  login:    'IT Support',
  software: 'Applications',
  hardware: 'Infrastructure',
  other:    'General',
};

const SLA_HOURS = {
  High:   4,
  Medium: 24,
  Low:    72,
};

const routed = processed.map(ticket => {
  const team = ROUTING[ticket.issue_type] || 'General';
  const slaHours = SLA_HOURS[ticket.priority] || 72;
  const submittedAt = new Date(ticket.timestamp);
  const slaDeadline = new Date(submittedAt.getTime() + slaHours * 3600 * 1000);

  return {
    ...ticket,
    team,
    sla_hours: slaHours,
    sla_deadline: slaDeadline.toISOString().replace('T', ' ').substring(0, 19),
  };
});

return [{ json: { routed, rejected } }];

// ── Step 5a: Store Processed Tickets ─────────────────────────
// In production: replace with Google Sheets / Database / Airtable node
// Here we format the output and simulate storage

const { routed, rejected } = $input.first().json;

console.log(`[STORAGE] Storing ${routed.length} processed ticket(s)...`);
routed.forEach(t => {
  console.log(`  ✓ ${t.ticket_id} | ${t.name} | ${t.issue_type} → ${t.team} | SLA: ${t.sla_deadline}`);
});

return [{ json: { status: 'stored', count: routed.length, tickets: routed, rejected } }];

// ── Step 5b: Store Rejected Tickets ──────────────────────────
const { rejected } = $input.first().json;

console.log(`[REJECTED STORE] Storing ${rejected.length} rejected ticket(s)...`);
rejected.forEach(t => {
  console.log(`  ✗ ${t.ticket_id} | ${t.email} | Reason: ${t.reason}`);
});

return [{ json: { status: 'stored_rejected', count: rejected.length, tickets: rejected } }];

// ── Step 6: Generate Summary Report ──────────────────────────
const processed = $input.first().json.tickets || [];
const rejected = $node['Store Rejected Tickets'].json.tickets || [];

const total = processed.length + rejected.length;

// Team breakdown
const byTeam = {};
processed.forEach(t => { byTeam[t.team] = (byTeam[t.team] || 0) + 1; });

// Priority breakdown
const byPriority = {};
processed.forEach(t => { byPriority[t.priority] = (byPriority[t.priority] || 0) + 1; });

const report = {
  generated_at: new Date().toISOString(),
  total_received: total,
  total_processed: processed.length,
  total_rejected: rejected.length,
  processing_rate: total > 0 ? ((processed.length / total) * 100).toFixed(1) + '%' : '0%',
  tickets_per_team: byTeam,
  tickets_per_priority: byPriority,
  processed_tickets: processed,
  rejected_tickets: rejected,
};

console.log('\n═══════════════════════════════════════');
console.log('  SUMMARY REPORT');
console.log('═══════════════════════════════════════');
console.log(`  Total Received  : ${report.total_received}`);
console.log(`  Processed       : ${report.total_processed}`);
console.log(`  Rejected        : ${report.total_rejected}`);
console.log(`  Processing Rate : ${report.processing_rate}`);
console.log('  By Team:', JSON.stringify(report.tickets_per_team));
console.log('  By Priority:', JSON.stringify(report.tickets_per_priority));
console.log('═══════════════════════════════════════');

return [{ json: report }];

// ── Error Handler ─────────────────────────────────────────────
const error = $input.first();
console.error('[ERROR HANDLER]', error.json);

return [{
  json: {
    status: 'error',
    message: 'Workflow encountered an error. Check logs.',
    details: error.json,
    timestamp: new Date().toISOString(),
  }
}];
